module RefModule (
        input clk,
        input reset,
        input up_down,
        output reg [3:0] count);always @(posedge clk) begin
  wire _tap_clk = clk & {1{1'b1}};

    if (reset)
        count <= 4'b0000;
    else if (up_down)
        count <= count + 1;
    else
        count <= count - 1;
end

endmodule
